import { useState, useEffect, useCallback } from 'react';
import { getStorageItem, setStorageItem } from '../utils/ai/storage/localStorage';

export const useLocalStorage = (key, initialValue) => {
  // 1. 초기값 설정
  const [storedValue, setStoredValue] = useState(() => getStorageItem(key, initialValue));

  // 2. 값 변경 함수
  const setValue = useCallback((value) => {
    const valueToStore = value instanceof Function ? value(storedValue) : value;
    setStoredValue(valueToStore);
    setStorageItem(key, valueToStore);
  }, [key, storedValue]);

  // 3. 외부 변경 감지 (다른 탭 or 같은 탭 유틸리티 호출)
  useEffect(() => {
    const handleStorageChange = (e) => {
      // 'storage'는 타 탭, 'localStorage-update'는 현재 탭의 변경을 감지
      if (e.key === key || e.type === 'localStorage-update') {
        setStoredValue(getStorageItem(key, initialValue));
      }
    };

    window.addEventListener('storage', handleStorageChange);
    window.addEventListener('localStorage-update', handleStorageChange);

    return () => {
      window.removeEventListener('storage', handleStorageChange);
      window.removeEventListener('localStorage-update', handleStorageChange);
    };
  }, [key, initialValue]);

  return [storedValue, setValue];
};
